ps.pstext:
if !IsFeatureImplemented(FEAT_SME_MOP4) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt('0'::Zn::'0');
let m : integer = UInt('1'::Zm::'0');
let nreg : integer{} = 1;
let mreg : integer = 2;
let da : integer = UInt(ZAda);
let sub_op : boolean = FALSE;

if !IsFeatureImplemented(FEAT_SME_MOP4) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt('0'::Zn::'0');
let m : integer = UInt('1'::Zm::'0');
let nreg : integer{} = 1;
let mreg : integer = 1;
let da : integer = UInt(ZAda);
let sub_op : boolean = FALSE;

if !IsFeatureImplemented(FEAT_SME_MOP4) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt('0'::Zn::'0');
let m : integer = UInt('1'::Zm::'0');
let nreg : integer{} = 2;
let mreg : integer = 1;
let da : integer = UInt(ZAda);
let sub_op : boolean = FALSE;

if !IsFeatureImplemented(FEAT_SME_MOP4) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt('0'::Zn::'0');
let m : integer = UInt('1'::Zm::'0');
let nreg : integer{} = 2;
let mreg : integer = 2;
let da : integer = UInt(ZAda);
let sub_op : boolean = FALSE;

CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let hvsize : integer{} = VL DIV 2;
let dim : integer{} = hvsize DIV 32;
let tilesize : integer{} = 4*dim*dim*32;
let op3 : bits(tilesize) = ZAtile{}(da, 32);
var result : bits(tilesize);

for outprod = 0 to 3 do
    let row_hv : integer = outprod DIVRM 2;
    let col_hv : integer = outprod MOD 2;
    let row_base : integer = row_hv * dim;
    let col_base : integer = col_hv * dim;

    let op1 : bits(VL) = Z{}(n + (nreg-1)*col_hv);
    let op2 : bits(VL) = Z{}(m + (mreg-1)*row_hv);

    for row = 0 to dim-1 do
        for col = 0 to dim-1 do
            let row_idx : integer = row_base + row;
            let col_idx : integer = col_base + col;
            let tile_idx : integer = row_idx * dim * 2 + col_idx;

            let sum : bits(32) = op3[tile_idx*:32];

            var erow_0 : bits(16) = op1[(2*row_idx + 0)*:16];
            var erow_1 : bits(16) = op1[(2*row_idx + 1)*:16];
            let ecol_0 : bits(16) = op2[(2*col_idx + 0)*:16];
            let ecol_1 : bits(16) = op2[(2*col_idx + 1)*:16];
            if sub_op then
                erow_0 = FPNeg{16}(erow_0, FPCR());
                erow_1 = FPNeg{16}(erow_1, FPCR());
            end;

            result[tile_idx*:32] = FPDotAdd_ZA(sum, erow_0, erow_1, ecol_0, ecol_1, FPCR());
        end;
    end;
end;
ZAtile{tilesize}(da, 32) = result;
